--
-- Table structure for table `activity_requests`
--

DROP TABLE IF EXISTS `activity_requests`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `activity_requests` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `request_number` varchar(255) DEFAULT NULL,
  `requested_by` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `vessel_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `activity_type` enum('INSPECTION','AUDIT','TRAINING','VISIT','OTHER') NOT NULL,
