56-563b-49c8-8880-337921608e07-scaled_9d5cbf0a-32da-4ec8-b530-3cf86cde38927545432768596844737.jpg\", \"field\": \"attendance_photo_url\"}',NULL,NULL,'2026-03-18 16:52:34','2026-03-18 16:52:34'),('865ac8f6-3322-4dfd-9c11-d949352aa19d','019c79a4-3eee-731a-9eff-b0eed303e215','GENERATE_SIGNED_URL','File',NULL,NULL,'{\"key\": \"documents/vessels/08afe220-7d5c-4b20-b4aa-a6f3d8c104fb-Screenshot 2026-03-03 at 10.54.08 AM.png\", \"expires_in\": 600}',NULL,NULL,'2026-03-06 15:56:27','2026-03-06 15:56:27'),('8672d3f2-1cfb-458a-9f9f-7b5c4a56bf1a','019c79a4-415c-758d-ad1b-48021901a0f1','GENERATE_SIGNED_URL','File',NULL,NULL,'{\"key\": \"documents/jobs/d976de46-4a09-4af3-9a7e-e4d17ffb80a5-# Girik Backend — End-to-End Job to Certificate Lifecycle.pdf\", \"expires_in\": 600}',NULL,NULL,'2026-03-09 08:57:51','2026-03-09 08:57:51'),('868c4f86-f3ad-4dd7-8fd6-5293b4104221','019c79a4-4930-71fd-aa73-887301791935','GENERATE_SIGNED_URL','File',NULL,NULL,'{\"key\": \"surveys/proofs/d6a5777e-71f0-4833-a31c-e622a4633b38-scaled_7821367a-761d-4493-914b-90e19492564c5044141665633413998.jpg\", \"field\": \"evidence_proof_url\"}',NULL,NULL,'2026-03-23 09:26:24','2026-03-23 09:26:24'),('86af4770-48cc-487b-bc89-e414c39da207','019c79a4-3eee-731a-9eff-b0eed303e215','CREATE_INVOICE','Payment','019d3dc1-93a1-727c-898d-644f47e1d49f',NULL,'{\"amount\": 1500, \"job_id\": \"019d3dc1-8b64-7689-bb97-5e1fad53937e\", \"currency\": \"USD\", \"payment_status\": \"UNPAID\"}',NULL,NULL,'2026-03-30 07:59:49','2026-03-30 07:59:49'),('86cbf6a8-8494-497e-b5dc-4b46faf39f8f','019c79a4-3eee-731a-9eff-b0eed303e215','UPDATE','SiteStaticContent','d4371572-6d45-41ec-8657-33b9ad401415','{\"id\": \"d4371572-6d45-41ec-8657-33b9ad401415\", \"slug\": \"terms-and-condition\", \"title\": \"Terms and condition\", \"body_html\": \"<p><strong>Last Updated: April 07, 2026</strong></p><h1>1. Introduction and Acceptance</h1><p>These Terms and Conditions (“Terms”) constitute a legally binding agreement between <strong>GRClass</strong> (“Company”, “We”, “Us”, or “Our”) and any individual or entity accessing or using the GRClass platform (“User”, “You”, or “Your”).</p><p>These Terms govern your access to and use of the GRClass digital platform, including but not limited to certification management, survey coordination, compliance tracking, reporting tools, and financial modules (collectively, the “Platform”).</p><p>By accessing or using the Platform, you confirm that you have read, understood, and agree to be bound by these Terms. If you do not agree with any part of these Terms, you must immediately discontinue use of the Platform.</p><h1>2. Scope of Service</h1><p>GRClass provides a digital infrastructure designed for maritime classification, inspection coordination, and certification lifecycle management, including:</p><h3>Certification Lifecycle</h3><ul><li>Requesting vessel certification</li><li>Technical review and approval workflow</li><li>Digital issuance and lifecycle tracking</li><li>Renewal and expiry management</li></ul><h3>Survey Management</h3><ul><li>Survey job requests and scheduling</li><li>Surveyor assignment and tracking</li><li>Inspection data submission</li><li>Evidence and report management</li></ul><h3>Compliance Tracking</h3><ul><li>Regulatory monitoring</li><li>Certificate validity tracking</li><li>Deficiency management</li><li>Compliance status dashboards</li></ul><h3>Financial Operations</h3><ul><li>Invoice generation and tracking</li><li>Payment status monitoring</li><li>Certification release upon payment clearance</li></ul><p><strong>Important:</strong> GRClass functions primarily as a digital facilitator and technical coordination platform. Physical inspections are performed only when covered under a separate service agreement or authorized survey arrangement.</p><h1>3. User Roles and Access Control</h1><p>The Platform operates using <strong>Role-Based Access Control (RBAC)</strong> to ensure data security and operational integrity. User roles may include:</p><ul><li>Client (Ship Owners / Managers)</li><li>Surveyor (Inspection Personnel)</li><li>Technical Staff (TO, TM, GM)</li><li>Administrator (System Management)</li></ul><p>Each user is granted permissions based strictly on their assigned role.</p><p>Users agree to:</p><ul><li>Access only authorized modules</li><li>Not attempt privilege escalation</li><li>Not access restricted data</li><li>Not manipulate system workflows</li></ul><p>Any attempt to bypass security controls or access unauthorized information may result in:</p><ul><li>Immediate account suspension</li><li>Permanent termination</li><li>Legal action if required</li></ul><h1>4. Account Responsibility and Security</h1><h3>Credential Responsibility</h3><p>Users are responsible for maintaining the confidentiality of login credentials. All activities performed under a user account are considered the responsibility of that account holder.</p><h3>Data Accuracy</h3><p>Users must provide accurate, complete, and up-to-date information during registration and platform usage.</p><h3>Unauthorized Access</h3><p>Users must immediately notify GRClass in case of:</p><ul><li>Suspected account compromise</li><li>Unauthorized access</li><li>Suspicious activity</li><li>Credential leakage</li></ul><p>GRClass shall not be liable for losses resulting from compromised user credentials.</p><h1>5. Job Requests and Survey Protocols</h1><h3>Request Submission</h3><p>Clients may submit vessel survey requests through the platform dashboard.</p><h3>Approval Discretion</h3><p>GRClass reserves the right to:</p><ul><li>Approve or reject survey requests</li><li>Assign surveyors</li><li>Request additional documentation</li><li>Modify survey scope</li></ul><h3>Surveyor Responsibilities</h3><p>Surveyors must:</p><ul><li>Submit accurate inspection findings</li><li>Provide supporting evidence</li><li>Upload photographs and documentation</li><li>Follow technical reporting standards</li></ul><h3>Report Verification</h3><p>GRClass may request:</p><ul><li>Report revision</li><li>Additional evidence</li><li>Re-inspection</li><li>Technical clarification</li></ul><p>If submitted reports do not meet technical standards.</p><h1>6. Certification Issuance and Validity</h1><p>Certificates are issued digitally based on:</p><ul><li>Successful survey completion</li><li>Technical review approval</li><li>Compliance verification</li><li>Payment confirmation</li></ul><h3>Certificate Validity</h3><p>Certificates are valid only for:</p><ul><li>The specified vessel</li><li>Defined scope</li><li>Mentioned duration</li><li>Applicable regulations</li></ul><h3>Revocation Rights</h3><p>GRClass reserves the right to:</p><ul><li>Suspend certificates</li><li>Modify certification scope</li><li>Revoke certificates</li><li>Place certificates on hold</li></ul><p>If:</p><ul><li>Non-compliance is detected</li><li>False data is submitted</li><li>Payment disputes arise</li><li>Regulatory requirements change</li></ul><h1>7. Financial Terms</h1><h3>Fees</h3><p>Users agree to pay all applicable fees related to:</p><ul><li>Surveys</li><li>Certification</li><li>Documentation</li><li>Technical services</li></ul><p>As per the current GRClass fee schedule.</p><h3>Payment Requirement</h3><p>Unless otherwise agreed in writing:</p><p>Certificates will remain in <strong>Pending Status</strong> until full payment is received.</p><h3>Late Payments</h3><p>GRClass reserves the right to:</p><ul><li>Suspend certificate issuance</li><li>Restrict platform access</li><li>Block new requests</li><li>Apply late payment restrictions</li></ul><p>For overdue invoices.</p><h1>8. Data Accuracy and Audit</h1><h3>User Responsibility</h3><p>Users remain responsible for:</p><ul><li>Vessel details accuracy</li><li>Uploaded documents</li><li>Technical information submitted</li><li>Compliance declarations</li></ul><h3>Audit Logs</h3><p>The platform maintains audit logs of:</p><ul><li>User login activity</li><li>Data changes</li><li>Certificate issuance</li><li>Survey submissions</li><li>System actions</li></ul><p>By using the platform, users consent to monitoring and auditing for:</p><ul><li>Security</li><li>Compliance</li><li>Regulatory requirements</li><li>Dispute resolution</li></ul><h1>9. Platform Availability and Maintenance</h1><p>GRClass targets high availability but does not guarantee:</p><ul><li>Uninterrupted access</li><li>Real-time processing</li><li>Immediate certificate issuance</li><li>Continuous uptime during maintenance</li></ul><p>The platform may experience:</p><ul><li>Scheduled maintenance</li><li>Emergency downtime</li><li>Server load delays</li><li>System upgrades</li></ul><p>GRClass shall not be liable for temporary unavailability.</p><h1>10. Limitation of Liability</h1><p>To the maximum extent permitted by law, GRClass shall not be liable for:</p><ul><li>Vessel operational losses</li><li>Business interruption</li><li>Survey delays</li><li>Regulatory authority decisions</li><li>Port State Control penalties</li><li>Flag State penalties</li><li>Certification delays</li><li>Third-party surveyor performance</li><li>Indirect or consequential damages</li></ul><p>Use of the platform is at the user\'s own risk.</p><h1>11. Intellectual Property</h1><p>All rights related to the platform remain the exclusive property of GRClass, including:</p><ul><li>Platform architecture</li><li>UI/UX design</li><li>Technical workflows</li><li>Survey templates</li><li>Certification formats</li><li>Algorithms</li><li>Database structure</li></ul><p>Users may not:</p><ul><li>Copy the system</li><li>Reverse engineer</li><li>Replicate workflows</li><li>Resell access</li><li>Distribute reports without permission</li></ul><p>Without prior written consent from GRClass.</p><h1>12. Confidentiality</h1><p>All information processed through the platform is considered confidential, including:</p><ul><li>Vessel data</li><li>Survey reports</li><li>Technical findings</li><li>Certification records</li><li>Client information</li></ul><p>Users agree not to:</p><ul><li>Share reports externally</li><li>Distribute screenshots</li><li>Share login access</li><li>Disclose internal workflows</li></ul><p>Without authorization.</p><p>GRClass maintains industry-standard security and encryption measures.</p><h1>13. Governing Law and Jurisdiction</h1><p>These Terms shall be governed by and interpreted in accordance with the laws of India.</p><p>Any disputes arising from these Terms shall be subject to the exclusive jurisdiction of the courts in <strong>Mumbai, India</strong>.</p><h1>14. Contact Information</h1><p>For legal, technical, or platform-related inquiries:</p><p><strong>GRClass Support Team</strong></p><p>Email: support@grclass.com</p><p><br></p><p>Address: PLC Mumbai</p><p>Website: <a href=\\\"http://www.grclass.com\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">www.grclass.com</a></p><h1>Acknowledgement</h1><p>By accessing or using the GRClass Platform, you acknowledge that:</p><ul><li>You have read these Terms</li><li>You understand these Terms</li><li>You agree to these Terms</li><li>You accept all responsibilities outlined herein</li></ul><p>Your continued use of the platform constitutes full acceptance of these Terms and Conditions.</p><p><br></p>\", \"createdAt\": \"2026-04-04T10:18:27.000Z\", \"faq_items\": null, \"updatedAt\": \"2026-04-10T04:16:51.000Z\", \"updated_by\": \"019c79a4-3eee-731a-9eff-b0eed303e215\", \"content_type\": \"PAGE\", \"is_published\": true, \"published_at\": \"2026-04-04T00:00:00.000Z\", \"thumbnail_url\": \"\"}','{\"id\": \"d4371572-6d45-41ec-8657-33b9ad401415\", \"slug\": \"terms-and-condition\", \"title\": \"Terms and condition\", \"body_html\": \"<h1>1. Introduction and Acceptance</h1><p>These Terms and Conditions (“Terms”) constitute a legally binding agreement between <strong>GRClass</strong> (“Company”, “We”, “Us”, or “Our”) and any individual or entity accessing or using the GRClass platform (“User”, “You”, or “Your”).</p><p>These Terms govern your access to and use of the GRClass digital platform, including but not limited to certification management, survey coordination, compliance tracking, reporting tools, and financial modules (collectively, the “Platform”).</p><p>By accessing or using the Platform, you confirm that you have read, understood, and agree to be bound by these Terms. If you do not agree with any part of these Terms, you must immediately discontinue use of the Platform.</p><h1>2. Scope of Service</h1><p>GRClass provides a digital infrastructure designed for maritime classification, inspection coordination, and certification lifecycle management, including:</p><h3>Certification Lifecycle</h3><ul><li>Requesting vessel certification</li><li>Technical review and approval workflow</li><li>Digital issuance and lifecycle tracking</li><li>Renewal and expiry management</li></ul><h3>Survey Management</h3><ul><li>Survey job requests and scheduling</li><li>Surveyor assignment and tracking</li><li>Inspection data submission</li><li>Evidence and report management</li></ul><h3>Compliance Tracking</h3><ul><li>Regulatory monitoring</li><li>Certificate validity tracking</li><li>Deficiency management</li><li>Compliance status dashboards</li></ul><h3>Financial Operations</h3><ul><li>Invoice generation and tracking</li><li>Payment status monitoring</li><li>Certification release upon payment clearance</li></ul><p><strong>Important:</strong> GRClass functions primarily as a digital facilitator and technical coordination platform. Physical inspections are performed only when covered under a separate service agreement or authorized survey arrangement.</p><h1>3. User Roles and Access Control</h1><p>The Platform operates using <strong>Role-Based Access Control (RBAC)</strong> to ensure data security and operational integrity. User roles may include:</p><ul><li>Client (Ship Owners / Managers)</li><li>Surveyor (Inspection Personnel)</li><li>Technical Staff (TO, TM, GM)</li><li>Administrator (System Management)</li></ul><p>Each user is granted permissions based strictly on their assigned role.</p><p>Users agree to:</p><ul><li>Access only authorized modules</li><li>Not attempt privilege escalation</li><li>Not access restricted data</li><li>Not manipulate system workflows</li></ul><p>Any attempt to bypass security controls or access unauthorized information may result in:</p><ul><li>Immediate account suspension</li><li>Permanent termination</li><li>Legal action if required</li></ul><h1>4. Account Responsibility and Security</h1><h3>Credential Responsibility</h3><p>Users are responsible for maintaining the confidentiality of login credentials. All activities performed under a user account are considered the responsibility of that account holder.</p><h3>Data Accuracy</h3><p>Users must provide accurate, complete, and up-to-date information during registration and platform usage.</p><h3>Unauthorized Access</h3><p>Users must immediately notify GRClass in case of:</p><ul><li>Suspected account compromise</li><li>Unauthorized access</li><li>Suspicious activity</li><li>Credential leakage</li></ul><p>GRClass shall not be liable for losses resulting from compromised user credentials.</p><h1>5. Job Requests and Survey Protocols</h1><h3>Request Submission</h3><p>Clients may submit vessel survey requests through the platform dashboard.</p><h3>Approval Discretion</h3><p>GRClass reserves the right to:</p><ul><li>Approve or reject survey requests</li><li>Assign surveyors</li><li>Request additional documentation</li><li>Modify survey scope</li></ul><h3>Surveyor Responsibilities</h3><p>Surveyors must:</p><ul><li>Submit accurate inspection findings</li><li>Provide supporting evidence</li><li>Upload photographs and documentation</li><li>Follow technical reporting standards</li></ul><h3>Report Verification</h3><p>GRClass may request:</p><ul><li>Report revision</li><li>Additional evidence</li><li>Re-inspection</li><li>Technical clarification</li></ul><p>If submitted reports do not meet technical standards.</p><h1>6. Certification Issuance and Validity