000;\\\" />\\n\\n<!-- Title -->\\n<h1 style=\\\"text-align:center;margin:10px 0;font-size:26px;\\\">\\nSAFETY EQUIPMENT CERTIFICATE\\n</h1>\\n\\n<p style=\\\"text-align:center;margin:0;\\\">\\nIssued under SOLAS 1974\\n</p>\\n\\n<hr style=\\\"margin:20px 0;border:1px solid #000;\\\" />\\n\\n<!-- Body -->\\n<table style=\\\"width:100%;border-collapse:collapse;font-size:15px;\\\">\\n\\n<tr>\\n<td style=\\\"padding:8px;width:40%\\\"><strong>Vessel Name</strong></td>\\n<td style=\\\"padding:8px\\\">{{vessel_name}}</td>\\n</tr>\\n\\n<tr>\\n<td style=\\\"padding:8px\\\"><strong>IMO Number</strong></td>\\n<td style=\\\"padding:8px\\\">{{imo_number}}</td>\\n</tr>\\n\\n<tr>\\n<td style=\\\"padding:8px\\\"><strong>Certificate Number</strong></td>\\n<td style=\\\"padding:8px\\\">{{certificate_number}}</td>\\n</tr>\\n\\n<tr>\\n<td style=\\\"padding:8px\\\"><strong>Issue Date</strong></td>\\n<td style=\\\"padding:8px\\\">{{issue_date}}</td>\\n</tr>\\n\\n<tr>\\n<td style=\\\"padding:8px\\\"><strong>Expiry Date</strong></td>\\n<td style=\\\"padding:8px\\\">{{expiry_date}}</td>\\n</tr>\\n\\n<tr>\\n<td style=\\\"padding:8px\\\"><strong>Port of Issue</strong></td>\\n<td style=\\\"padding:8px\\\">{{port}}</td>\\n</tr>\\n\\n</table>\\n\\n<!-- Statement -->\\n<p style=\\\"margin-top:30px;line-height:1.6;text-align:justify;\\\">\\nThis is to certify that the safety equipment of the above named vessel has been\\nsurveyed in accordance with the requirements of the International Convention\\nfor the Safety of Life at Sea (SOLAS), 1974, as amended, and found to be in\\ncompliance with the applicable provisions.\\n</p>\\n\\n<!-- Signature -->\\n<table style=\\\"width:100%;margin-top:60px;\\\">\\n<tr>\\n\\n<td style=\\\"text-align:left;\\\">\\n_________________________<br/>\\nPlace: {{place}}\\n</td>\\n\\n<td style=\\\"text-align:right;\\\">\\n_________________________<br/>\\nAuthorized Signatory\\n</td>\\n\\n</tr>\\n</table>\\n\\n<!-- Footer -->\\n<div style=\\\"margin-top:40px;font-size:12px