INSERT INTO `certificate_templates` VALUES ('019cbf1d-bf72-779a-a8b3-98a6b2c476a1','019cbf1d-bdc2-75e8-9fc8-3d161ae90ede','Safety Equipment Certificate – Official Template v1','<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<title>Safety Equipment Certificate</title>\n</head>\n\n<body style=\"margin:0;padding:0;background:#f5f7fb;font-family:serif;\">\n\n<div style=\"width:800px;margin:40px auto;background:#ffffff;padding:40px;border:1px solid #000;\">\n\n<!-- Header -->\n<div style=\"text-align:center;margin-bottom:20px;\">\n<h2 style=\"margin:0;\">GR CLASS</h2>\n<div>Classification & Certification</div>\n</div>\n\n<hr style=\"margin:20px 0;border:1px solid #000;\" />\n\n<!-- Title -->\n<h1 style=\"text-align:center;margin:10px 0;font-size:26px;\">\nSAFETY EQUIPMENT CERTIFICATE\n</h1>\n\n<p style=\"text-align:center;margin:0;\">\nIssued under SOLAS 1974\n</p>\n\n<hr style=\"margin:20px 0;border:1px solid #000;\" />\n\n<!-- Body -->\n<table style=\"width:100%;border-collapse:collapse;font-size:15px;\">\n\n<tr>\n<td style=\"padding:8px;width:40%\"><strong>Vessel Name</strong></td>\n<td style=\"padding:8px\">{{vessel_name}}</td>\n</tr>\n\n<tr>\n<td style=\"padding:8px\"><strong>IMO Number</strong></td>\n<td style=\"padding:8px\">{{imo_number}}</td>\n</tr>\n\n<tr>\n<td style=\"padding:8px\"><strong>Certificate Number</strong></td>\n<td style=\"padding:8px\">{{certificate_number}}</td>\n</tr>\n\n<tr>\n<td style=\"padding:8px\"><strong>Issue Date</strong></td>\n<td style=\"padding:8px\">{{issue_date}}</td>\n</tr>\n\n<tr>\n<td style=\"padding:8px\"><strong>Expiry Date</strong></td>\n<td style=\"padding:8px\">{{expiry_date}}</td>\n</tr>\n\n<tr>\n<td style=\"padding:8px\"><strong>Port of Issue</strong></td>\n<td style=\"padding:8px\">{{port}}</td>\n</tr>\n\n</table>\n\n<!-- Statement -->\n<p style=\"margin-top:30px;line-height:1.6;text-align:justify;\">\nThis is to certify that the safety equipment of the above named vessel has been\nsurveyed in accordance with the requirements of the International Convention\nfor the Safety of Life at Sea (SOLAS), 1974, as amended, and found to be in\ncompliance with the applicable provisions.\n</p>\n\n<!-- Signature -->\n<table style=\"width:100%;margin-top:60px;\">\n<tr>\n\n<td style=\"text-align:left;\">\n_________________________<br/>\nPlace: {{place}}\n</td>\n\n<td style=\"text-align:right;\">\n_________________________<br/>\nAuthorized Signatory\n</td>\n\n</tr>\n</table>\n\n<!-- Footer -->\n<div style=\"margin-top:40px;font-size:12px;text-align:center;\">\nGR Class — Classification & Certification Authority\n</div>\n\n</div>\n\n</body>\n</html>','[\"vessel_name\", \"imo_number\", \"certificate_number\", \"issue_date\", \"expiry_date\"]',1,'2026-03-05 17:48:43','2026-04-10 04:59:40'),('019cbf1d-c82e-77fa-8610-ef07721481c9','019cbf1d-c73f-7228-bae8-36733fc00120','International Load Line Certificate – Official Template v1','<div style=\"font-family:serif;padding:40px\"><h1 style=\"text-align:center\">INTERNATIONAL LOAD LINE CERTIFICATE</h1><p style=\"text-align:center\">Issued under Load Lines Convention 1966</p><hr/><table style=\"width:100%\"><tr><td><strong>Vessel:</strong></td><td>{{vessel_name}}</td></tr><tr><td><strong>IMO:</strong></td><td>{{imo_number}}</td></tr><tr><td><strong>Certificate No:</strong></td><td>{{certificate_number}}</td></tr><tr><td><strong>Issue Date:</strong></td><td>{{issue_date}}</td></tr><tr><td><strong>Expiry Date:</strong></td><td>{{expiry_date}}</td></tr></table></div>','[\"vessel_name\", \"imo_number\", \"certificate_number\", \"issue_date\", \"expiry_date\"]',1,'2026-03-05 17:48:45','2026-03-05 17:48:45'),('019cbf1d-ce1d-7711-a10f-7d173736674d','019cbf1d-cd29-7749-bc45-f25779643010','IOPP Certificate – Official Template v1','<div style=\"font-family:serif;padding:40px\"><h1 style=\"text-align:center\">IOPP CERTIFICATE</h1><p style=\"text-align:center\">Issued under MARPOL 73/78 Annex I</p><hr/><table style=\"width:100%\"><tr><td><strong>Vessel:</strong></td><td>{{vessel_name}}</td></tr><tr><td><strong>IMO:</strong></td><td>{{imo_number}}</td></tr><tr><td><strong>Certificate No:</strong></td><td>{{certificate_number}}</td></tr><tr><td><strong>Issue Date:</strong></td><td>{{issue_date}}</td></tr><tr><td><strong>Expiry Date:</strong></td><td>{{expiry_date}}</td></tr></table></div>','[\"vessel_name\", \"imo_number\", \"certificate_number\", \"issue_date\", \"expiry_date\"]',1,'2026-03-05 17:48:47','2026-03-05 17:48:47'),('019cbf1d-d484-7408-8e7a-e567054db5b7','019cbf1d-d356-7408-86c1-2b54130a4f1a','Safety Construction Certificate – Official Template v1','<div style=\"font-family:serif;padding:40px\"><h1 style=\"text-align:center\">SAFETY CONSTRUCTION CERTIFICATE</h1><p style=\"text-align:center\">Issued under SOLAS 1974</p><hr/><table style=\"width:100%\"><tr><td><strong>Vessel:</strong></td><td>{{vessel_name}}</td></tr><tr><td><strong>IMO:</strong></td><td>{{imo_number}}</td></tr><tr><td><strong>Certificate No:</strong></td><td>{{certificate_number}}</td></tr><tr><td><strong>Issue Date:</strong></td><td>{{issue_date}}</td></tr><tr><td><strong>Expiry Date:</strong></td><td>{{expiry_date}}</td></tr></table></div>','[\"vessel_name\", \"imo_number\", \"certificate_number\", \"issue_date\", \"expiry_date\"]',1,'2026-03-05 17:48:49','2026-03-05 17:48:49');
/*!40000 ALTER TABLE `certificate_templates` ENABLE KEYS */;
