INSERT INTO `certificate_types` VALUES ('019cbf1d-bdc2-75e8-9fc8-3d161ae90ede','Safety Equipment Certificate','SE','CLASS',5,'ACTIVE','Certifies that the ship complies with SOLAS regarding life-saving appliances, fire safety systems, and navigational equipment.',1),('019cbf1d-c73f-7228-bae8-36733fc00120','International Load Line Certificate','LL','CLASS',5,'ACTIVE','Certifies the freeboards assigned to the ship per the International Convention on Load Lines, 1966.',1),('019cbf1d-cd29-7749-bc45-f25779643010','IOPP Certificate','IOP','FLAG',5,'ACTIVE','International Oil Pollution Prevention Certificate — MARPOL Annex I compliance.',1),('019cbf1d-d356-7408-86c1-2b54130a4f1a','Safety Construction Certificate','SC','CLASS',5,'ACTIVE','Certifies structural strength, subdivision, stability, machinery comply with SOLAS.',1);
/*!40000 ALTER TABLE `certificate_types` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `certificates`
--

DROP TABLE IF EXISTS `certificates`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `certificates` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `vessel_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `certificate_type_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `certificate_number` varchar(255) DEFAULT NULL,
  `issue_date` date DEFAULT NULL,
  `expiry_date` date DEFAULT NULL,
  `status` enum('VALID','EXPIRED','SUSPENDED','REVOKED') DEFAULT 'VALID',
  `qr_code_url` varchar(255) DEFAULT NULL,
  `pdf_file_url` varchar(255) DEFAULT NULL,
  `issued_by_user_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `certificate_number` (`certificate_number`),
  UNIQUE KEY `certificate_number_2` (`certificate_number`),
  KEY `certificates_certificate_number` (`certificate_number`),
  KEY `certificates_vessel_id` (`vessel_id`),
  KEY `certificates_status` (`status`),
  KEY `idx_cert_vessel_id` (`vessel_id`),
  KEY `idx_cert_cert_type_id` (`certificate_type_id`),
  KEY `idx_cert_status` (`status`),
  KEY `idx_cert_expiry_date` (`expiry_date`),
  KEY `idx_cert_cert_number` (`certificate_number`),
  KEY `issued_by_user_id` (`issued_by_user_id`),
  CONSTRAINT `certificates_ibfk_4` FOREIGN KEY (`vessel_id`) REFERENCES `vessels` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `certificates_ibfk_5` FOREIGN KEY (`certificate_type_id`) REFERENCES `certificate_types` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `certificates_ibfk_6` FOREIGN KEY (`issued_by_user_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

