INSERT INTO `checklist_templates` VALUES ('019cbf1d-c109-770e-8cdb-a70a3decdbfc','Safety Equipment Certificate Survey Checklist','CHK-SEC-001','Comprehensive inspection checklist for Safety Equipment Certificate.','019cbf1d-bdc2-75e8-9fc8-3d161ae90ede','[{\"items\": [{\"code\": \"LSA-01\", \"text\": \"Lifeboats condition and davit operation\", \"type\": \"PASS_FAIL\"}, {\"code\": \"LSA-02\", \"text\": \"Liferafts hydrostatic release units\", \"type\": \"PASS_FAIL\"}, {\"code\": \"LSA-03\", \"text\": \"Lifebuoys quantity and condition\", \"type\": \"YES_NO\"}, {\"code\": \"LSA-04\", \"text\": \"Immersion suits available for each crew member\", \"type\": \"YES_NO\"}, {\"code\": \"LSA-05\", \"text\": \"EPIRB registration and battery validity\", \"type\": \"PASS_FAIL\"}], \"title\": \"Life-Saving Appliances\"}, {\"items\": [{\"code\": \"FSS-01\", \"text\": \"Fixed fire extinguishing systems tested\", \"type\": \"PASS_FAIL\"}, {\"code\": \"FSS-02\", \"text\": \"Fire detection and alarm system operational\", \"type\": \"PASS_FAIL\"}, {\"code\": \"FSS-03\", \"text\": \"Portable fire extinguishers serviced\", \"type\": \"YES_NO\"}, {\"code\": \"FSS-04\", \"text\": \"Fire hoses and nozzles in good condition\", \"type\": \"YES_NO\"}], \"title\": \"Fire Safety Systems\"}, {\"items\": [{\"code\": \"NAV-01\", \"text\": \"Radar systems X-band and S-band operational\", \"type\": \"PASS_FAIL\"}, {\"code\": \"NAV-02\", \"text\": \"AIS transponder functioning correctly\", \"type\": \"PASS_FAIL\"}, {\"code\": \"NAV-03\", \"text\": \"GMDSS equipment tested\", \"type\": \"PASS_FAIL\"}], \"title\": \"Navigation Equipment\"}]','ACTIVE','{\"version\": \"1.0\", \"applicable_vessel_types\": [\"Bulk Carrier\", \"Oil Tanker\", \"Container Ship\", \"Chemical Tanker\", \"LPG Carrier\", \"General Cargo\"]}','019c79a4-3eee-731a-9eff-b0eed303e215',NULL,'2026-03-05 17:48:44','2026-03-05 17:48:44'),('019cbf1d-c90d-76ee-bc24-847429a2674d','International Load Line Certificate Survey Checklist','CHK-ILLC-001','Comprehensive inspection checklist for International Load Line Certificate.','019cbf1d-c73f-7228-bae8-36733fc00120','[{\"items\": [{\"code\": \"HUL-01\", \"text\": \"Condition of shell plating\", \"type\": \"PASS_FAIL\"}, {\"code\": \"HUL-02\", \"text\": \"Deck plating integrity around openings\", \"type\": \"PASS_FAIL\"}, {\"code\": \"HUL-03\", \"text\": \"Load line marks clearly visible\", \"type\": \"YES_NO\"}, {\"code\": \"HUL-04\", \"text\": \"Draft marks legible on all sides\", \"type\": \"YES_NO\"}], \"title\": \"Hull & Structural Integrity\"}, {\"items\": [{\"code\": \"WTC-01\", \"text\": \"Hatch covers weathertight and operational\", \"type\": \"PASS_FAIL\"}, {\"code\": \"WTC-02\", \"text\": \"Ventilators and air pipes closures\", \"type\": \"PASS_FAIL\"}, {\"code\": \"WTC-03\", \"text\": \"Scuppers and freeing ports condition\", \"type\": \"PASS_FAIL\"}, {\"code\": \"WTC-04\", \"text\": \"Watertight doors operational test\", \"type\": \"PASS_FAIL\"}], \"title\": \"Watertight Closures\"}, {\"items\": [{\"code\": \"GRW-01\", \"text\": \"Guard rails and stanchions secured\", \"type\": \"YES_NO\"}, {\"code\": \"GRW-02\", \"text\": \"Gangway and walkway condition\", \"type\": \"YES_NO\"}], \"title\": \"Guard Rails & Walkways\"}]','ACTIVE','{\"version\": \"1.0\", \"applicable_vessel_types\": [\"Bulk Carrier\", \"Oil Tanker\", \"Container Ship\", \"Chemical Tanker\", \"LPG Carrier\", \"General Cargo\"]}','019c79a4-3eee-731a-9eff-b0eed303e215',NULL,'2026-03-05 17:48:46','2026-03-05 17:48:46'),('019cbf1d-cee5-7177-aa20-2217f0641e43','IOPP Certificate Survey Checklist','CHK-IC-001','Comprehensive inspection checklist for IOPP Certificate.','019cbf1d-cd29-7749-bc45-f25779643010','[{\"items\": [{\"code\": \"ODM-01\", \"text\": \"Oil discharge monitoring equipment calibrated\", \"type\": \"PASS_FAIL\"}, {\"code\": \"ODM-02\", \"text\": \"Oil-water separator operational and tested\", \"type\": \"PASS_FAIL\"}, {\"code\": \"ODM-03\", \"text\": \"15 ppm bilge alarm functional\", \"type\": \"PASS_FAIL\"}], \"title\": \"Oil Discharge Monitoring\"}, {\"items\": [{\"code\": \"FOT-01\", \"text\": \"Double hull / double bottom arrangement compliant\", \"type\": \"YES_NO\"}, {\"code\": \"FOT-02\", \"text\": \"Fuel oil tank overflow prevention\", \"type\": \"PASS_FAIL\"}, {\"code\": \"FOT-03\", \"text\": \"Oil residue (sludge) tank capacity adequate\", \"type\": \"YES_NO\"}], \"title\": \"Fuel Oil Tank Protection\"}, {\"items\": [{\"code\": \"SOD-01\", \"text\": \"Oil Record Book Part I maintained\", \"type\": \"YES_NO\"}, {\"code\": \"SOD-02\", \"text\": \"SOPEP onboard and current\", \"type\": \"YES_NO\"}, {\"code\": \"SOD-03\", \"text\": \"Crew drilled on oil spill procedures\", \"type\": \"YES_NO\"}], \"title\": \"Ship Operations & Documentation\"}]','ACTIVE','{\"version\": \"1.0\", \"applicable_vessel_types\": [\"Bulk Carrier\", \"Oil Tanker\", \"Container Ship\", \"Chemical Tanker\", \"LPG Carrier\", \"General Cargo\"]}','019c79a4-3eee-731a-9eff-b0eed303e215',NULL,'2026-03-05 17:48:47','2026-03-05 17:48:47'),('019cbf1d-d553-731a-8929-f47e88a5e2eb','Safety Construction Certificate Survey Checklist','CHK-SCC-001','Comprehensive inspection checklist for Safety Construction Certificate.','019cbf1d-d356-7408-86c1-2b54130a4f1a','[{\"items\": [{\"code\": \"STR-01\", \"text\": \"Hull girder strength assessment\", \"type\": \"PASS_FAIL\"}, {\"code\": \"STR-02\", \"text\": \"Frame and bracket condition\", \"type\": \"PASS_FAIL\"}, {\"code\": \"STR-03\", \"text\": \"Bulkhead watertight integrity\", \"type\": \"PASS_FAIL\"}], \"title\": \"Structural Strength\"}, {\"items\": [{\"code\": \"MCH-01\", \"text\": \"Main engine condition and performance\", \"type\": \"PASS_FAIL\"}, {\"code\": \"MCH-02\", \"text\": \"Auxiliary engines operational\", \"type\": \"PASS_FAIL\"}, {\"code\": \"MCH-03\", \"text\": \"Emergency generator tested\", \"type\": \"PASS_FAIL\"}, {\"code\": \"MCH-04\", \"text\": \"Steering gear test (including emergency)\", \"type\": \"PASS_FAIL\"}], \"title\": \"Machinery & Electrical\"}, {\"items\": [{\"code\": \"STB-01\", \"text\": \"Stability information booklet onboard\", \"type\": \"YES_NO\"}, {\"code\": \"STB-02\", \"text\": \"Loading computer operational (if applicable)\", \"type\": \"YES_NO\"}], \"title\": \"Stability & Subdivision\"}, {\"items\": [{\"code\": \"her-001\", \"text\": \"cacacs\", \"type\": \"YES_NO_NA\"}], \"title\": \"hello ji \"}]','INACTIVE','{\"version\": \"1.0\", \"applicable_vessel_types\": [\"Bulk Carrier\", \"Oil Tanker\", \"Container Ship\", \"Chemical Tanker\", \"LPG Carrier\", \"General Cargo\"]}','019c79a4-3eee-731a-9eff-b0eed303e215','019c79a4-3eee-731a-9eff-b0eed303e215','2026-03-05 17:48:49','2026-04-10 04:41:31'),('019d756e-2c6c-7229-9222-647f0b70b658','Safety Construction Certificate Survey Checklist','CHK-SCC-001_V2_0','Comprehensive inspection checklist for Safety Construction Certificate.','019cbf1d-d356-7408-86c1-2b54130a4f1a','[{\"items\": [{\"code\": \"STR-01\", \"text\": \"Hull girder strength assessment\", \"type\": \"PASS_FAIL\"}, {\"code\": \"STR-02\", \"text\": \"Frame and bracket condition\", \"type\": \"PASS_FAIL\"}, {\"code\": \"STR-03\", \"text\": \"Bulkhead watertight integrity\", \"type\": \"PASS_FAIL\"}], \"title\": \"Structural Strength\"}, {\"items\": [{\"code\": \"MCH-01\", \"text\": \"Main engine condition and performance\", \"type\": \"PASS_FAIL\"}, {\"code\": \"MCH-02\", \"text\": \"Auxiliary engines operational\", \"type\": \"PASS_FAIL\"}, {\"code\": \"MCH-03\", \"text\": \"Emergency generator tested\", \"type\": \"PASS_FAIL\"}, {\"code\": \"MCH-04\", \"text\": \"Steering gear test (including emergency)\", \"type\": \"PASS_FAIL\"}], \"title\": \"Machinery & Electrical\"}, {\"items\": [{\"code\": \"STB-01\", \"text\": \"Stability information booklet onboard\", \"type\": \"YES_NO\"}, {\"code\": \"STB-02\", \"text\": \"Loading computer operational (if applicable)\", \"type\": \"YES_NO\"}], \"title\": \"Stability & Subdivision\"}]','ACTIVE','{\"version\": \"2.0\", \"applicable_vessel_types\": [\"Bulk Carrier\", \"Oil Tanker\", \"Container Ship\", \"Chemical Tanker\", \"LPG Carrier\", \"General Cargo\"]}','019c79a4-3eee-731a-9eff-b0eed303e215','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-10 03:27:27','2026-04-10 04:41:32'),('019d75c4-3617-7579-af4e-06fb931adadd','IOPP Certificate Survey Checklist','CHK-IC-001_V2_0','Comprehensive inspection checklist for IOPP Certificate.','019cbf1d-cd29-7749-bc45-f25779643010','[{\"items\": [{\"code\": \"ODM-01\", \"text\": \"Oil discharge monitoring equipment calibrated\", \"type\": \"PASS_FAIL\"}, {\"code\": \"ODM-02\", \"text\": \"Oil-water separator operational and tested\", \"type\": \"PASS_FAIL\"}, {\"code\": \"ODM-03\", \"text\": \"15 ppm bilge alarm functional\", \"type\": \"PASS_FAIL\"}], \"title\": \"Oil Discharge Monitoring\"}, {\"items\": [{\"code\": \"FOT-01\", \"text\": \"Double hull / double bottom arrangement compliant\", \"type\": \"YES_NO\"}, {\"code\": \"FOT-02\", \"text\": \"Fuel oil tank overflow prevention\", \"type\": \"PASS_FAIL\"}, {\"code\": \"FOT-03\", \"text\": \"Oil residue (sludge) tank capacity adequate\", \"type\": \"YES_NO\"}], \"title\": \"Fuel Oil Tank Protection\"}, {\"items\": [{\"code\": \"SOD-01\", \"text\": \"Oil Record Book Part I maintained\", \"type\": \"YES_NO\"}, {\"code\": \"SOD-02\", \"text\": \"SOPEP onboard and current\", \"type\": \"YES_NO\"}, {\"code\": \"SOD-03\", \"text\": \"Crew drilled on oil spill procedures\", \"type\": \"YES_NO\"}, {\"code\": \"SOD-04\", \"text\": \"Is evrything ok\", \"type\": \"YES_NO_NA\"}], \"title\": \"Ship Operations & Documentation\"}]','DRAFT','{\"version\": \"2.0\", \"applicable_vessel_types\": [\"Bulk Carrier\", \"Oil Tanker\", \"Container Ship\", \"Chemical Tanker\", \"LPG Carrier\", \"General Cargo\"]}','019c79a4-3eee-731a-9eff-b0eed303e215','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-10 05:01:26','2026-04-10 05:01:50');
