DROP TABLE IF EXISTS `job_requests`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `job_requests` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `vessel_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `requested_by_user_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `certificate_type_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `reason` text,
  `target_port` varchar(255) DEFAULT NULL,
  `target_date` date DEFAULT NULL,
  `job_status` enum('CREATED','DOCUMENT_VERIFIED','APPROVED','ASSIGNED','SURVEY_AUTHORIZED','IN_PROGRESS','SURVEY_DONE','REVIEWED','FINALIZED','REWORK_REQUESTED','PAYMENT_DONE','CERTIFIED','REJECTED') DEFAULT 'CREATED',
  `assigned_surveyor_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `assigned_by_user_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `generated_certificate_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `approved_by_user_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `remarks` text,
  `created_at` datetime NOT NULL,
  `is_survey_required` tinyint(1) DEFAULT '1',
  `reschedule_count` int DEFAULT '0',
  `priority` enum('LOW','NORMAL','HIGH','URGENT') NOT NULL DEFAULT 'NORMAL' COMMENT 'Job priority set via PUT /:id/priority by ADMIN/GM/TM',
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `job_requests_vessel_id` (`vessel_id`),
  KEY `job_requests_requested_by_user_id` (`requested_by_user_id`),
  KEY `job_requests_job_status` (`job_status`),
  KEY `idx_jobreq_vessel_id` (`vessel_id`),
  KEY `idx_jobreq_job_status` (`job_status`),
  KEY `idx_jobreq_assigned_surveyor` (`assigned_surveyor_id`),
  KEY `idx_jobreq_cert_type_id` (`certificate_type_id`),
  KEY `idx_jobreq_requested_by` (`requested_by_user_id`),
  KEY `idx_jobreq_created_at` (`created_at`),
  KEY `idx_jobreq_updated_at` (`updated_at`),
  KEY `assigned_by_user_id` (`assigned_by_user_id`),
  KEY `generated_certificate_id` (`generated_certificate_id`),
  KEY `approved_by_user_id` (`approved_by_user_id`),
  CONSTRAINT `job_requests_ibfk_10` FOREIGN KEY (`certificate_type_id`) REFERENCES `certificate_types` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `job_requests_ibfk_11` FOREIGN KEY (`assigned_surveyor_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `job_requests_ibfk_12` FOREIGN KEY (`assigned_by_user_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `job_requests_ibfk_13` FOREIGN KEY (`generated_certificate_id`) REFERENCES `certificates` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `job_requests_ibfk_14` FOREIGN KEY (`approved_by_user_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `job_requests_ibfk_8` FOREIGN KEY (`vessel_id`) REFERENCES `vessels` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `job_requests_ibfk_9` FOREIGN KEY (`requested_by_user_id`) REFERENCES `users` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
