INSERT INTO `site_static_contents` VALUES ('065e72de-3efd-40eb-a081-eb43f6b31a26','privacy-and-compliance','Privacy and Regulatory Compliance Policy','PAGE','<h2>Introduction</h2><p>GR Class is committed to protecting the privacy, confidentiality, and integrity of all information handled within its systems. This Privacy and Regulatory Compliance Policy defines how data is collected, processed, stored, and protected in accordance with applicable laws and international standards.</p><h2>Scope</h2><p>This policy applies to all data managed by GR Class, including information related to clients, vessels, operations, employees, and system users. It covers both digital and physical data across all operational environments.</p><h2>Data Collection</h2><p>GR Class collects only the information necessary to provide its services effectively. This may include:</p><ul><li>Vessel and operational information</li><li>Client and organizational details</li><li>Contact information such as email addresses and phone numbers</li><li>Certification and compliance records</li><li>System access logs and usage data</li></ul><p>All data collection is conducted in a lawful and transparent manner.</p><h2>Purpose of Data Usage</h2><p>The information collected is used for the following purposes:</p><ul><li>Processing and issuing certifications</li><li>Conducting inspections and compliance assessments</li><li>Managing operational workflows</li><li>Communicating with clients and stakeholders</li><li>Improving service delivery and system performance</li><li>Ensuring compliance with legal and regulatory requirements</li></ul><h2>Data Protection and Security</h2><p>GR Class implements comprehensive security measures to safeguard data against unauthorized access, alteration, disclosure, or loss. These measures include:</p><ul><li>Encryption of sensitive data</li><li>Secure server and infrastructure management</li><li>Access control mechanisms and authentication protocols</li><li>Continuous monitoring and threat detection systems</li><li>Regular security audits and vulnerability assessments</li></ul><h2>Access Control</h2><p>Access to data is strictly controlled based on roles and responsibilities. Only authorized personnel are permitted to access specific data required for their duties. Access rights are reviewed periodically to ensure continued compliance with security policies.</p><h2>Data Retention</h2><p>Data is retained only for as long as necessary to fulfill operational, contractual, and legal obligations. Once the retention period expires:</p><ul><li>Data is securely deleted or anonymized</li><li>Proper disposal procedures are followed</li><li>Compliance with applicable data retention regulations is ensured</li></ul><h2>Regulatory Compliance</h2><p>GR Class adheres to relevant international data protection laws and maritime regulations. The organization ensures that all processes align with:</p><ul><li>Global data protection principles</li><li>Maritime compliance standards</li><li>Industry-specific regulatory frameworks</li></ul><p>Compliance is continuously monitored and updated in response to regulatory changes.</p><h2>Transparency and User Rights</h2><p>GR Class maintains transparency in its data handling practices. Where applicable, individuals have the right to:</p><ul><li>Access their personal data</li><li>Request correction of inaccurate information</li><li>Request deletion of data, subject to legal and operational requirements</li><li>Obtain information about how their data is processed</li></ul><h2>Data Sharing</h2><p>GR Class does not sell or misuse data. Information may be shared only under the following conditions:</p><ul><li>With regulatory authorities, where required by law</li><li>With authorized partners involved in service delivery</li><li>With legal entities for compliance and enforcement purposes</li></ul><p>All third parties are required to adhere to strict data protection standards.</p><h2>Incident Management</h2><p>In the event of a data breach or security incident, GR Class follows a structured response process:</p><ul><li>Immediate identification and containment of the issue</li><li>Assessment of impact and risk</li><li>Notification to affected parties, where required</li><li>Implementation of corrective and preventive measures</li></ul><h2>Continuous Improvement</h2><p>GR Class regularly reviews and updates its privacy and compliance practices to ensure alignment with evolving legal, technological, and industry standards. Continuous improvement is a key component of maintaining data security and user trust.</p><h2>Contact Information</h2><p>For any questions or concerns related to privacy and data protection, users may contact:</p><p>Email: info@grclass.com</p>','',NULL,1,'2026-04-04 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 09:18:01','2026-04-10 03:28:27'),('207b649f-8be0-4b45-be2a-d9816d44208c','girik-class-expands-network-middle-east','Expansion: Girik Class Opens New Survey Hub in Dubai','NEWS','<h2 class=\"ql-align-justify\"><span class=\"ql-font-serif\" style=\"color: rgb(230, 0, 0); font-size: 32px;\">Boosting Services in the GCC Region</span></h2><p class=\"ql-align-justify\"><span class=\"ql-font-serif\" style=\"font-size: 20px;\">To better serve our growing fleet in the Middle East, Girik Class is excited to announce the opening of its latest technical hub in Dubai, UAE.</span></p><p class=\"ql-align-justify\"><span class=\"ql-font-serif\" style=\"font-size: 20px;\">This new facility will house five senior surveyors and a dedicated technical team for rapid response to vessel inspection requests in Port Rashid, Jebel Ali, and surrounding regions.</span></p>','https://cdn.grclass.com/website/thumbnails/37e7fe03-eda6-4e83-88b2-749ed7d0e4e1-screen.png',NULL,1,'2026-03-20 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 09:18:01','2026-04-07 16:56:08'),('698ab5ed-c191-42fb-8ef1-a48a002cab04','faq','Certification and Survey – Frequently Asked Questions','FAQ',NULL,'','[{\"answer\": \"Classification surveys ensure a vessel meets the technical rules of the RO regarding structural integrity and machinery. Statutory surveys are performed on behalf of Flag States to ensure compliance with international conventions like SOLAS, MARPOL, and Load Line.\", \"question\": \"What is the difference between Classification and Statutory surveys?\", \"sort_order\": 0}, {\"answer\": \"Surveys can be scheduled via the Girik Ops portal. Once a request is submitted, our operations team assigns a surveyor based on location and expertise. Clients can track the status from \\\"Assigned\\\" to \\\"Certified\\\" in real-time.\", \"question\": \"How do I book an Annual or Renewal survey?\", \"sort_order\": 1}, {\"answer\": \"Yes. All certificates issued by Girik Class are digitally signed and include a secure QR code for instant verification by Port State Control (PSC) and other authorities, ensuring full compliance with IMO guidelines.\", \"question\": \"Are digital certificates issued by Girik Class legally valid?\", \"sort_order\": 2}, {\"answer\": \"If a deficiency is noted, a \\\"Non-Conformity\\\" or \\\"Condition of Class\\\" is issued. The shipowner is provided with a timeline for rectification. Once the rectifications are verified, the surveyor will update the status for final certificate issuance.\", \"question\": \"What happens if a deficiency is found during a survey?\", \"sort_order\": 3}, {\"answer\": \"Girik Class is authorized by several prominent flag states to act as their Recognized Organization. Contact our compliance department at compliance@grclass.com for the full list of authorizations.\", \"question\": \"Which flag administrations recognize Girik Class?\", \"sort_order\": 4}]',1,'2026-04-04 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 09:18:00','2026-04-04 10:36:01'),('74539be1-2eed-4c4b-9264-ae3a833fc279','technology-immutable-1blockchain-verification-now-live','Technology: Immutable Blockchain Verification Now Live','NEWS','<h2>Ending Maritime Fraud</h2><p>Girik Class has successfully integrated blockchain technology into its digital certification pipeline.</p><p>Every certificate issued from today onwards will be permanently anchored to a secure ledger, allowing Port State Control and shipowners to verify authenticity in seconds without contacting our head office.</p>','https://cdn.grclass.com/website/thumbnails/7db54bbd-d861-4e53-adc4-bb33d1f0393d-screen.png',NULL,1,'2026-04-09 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-07 16:32:22','2026-04-07 16:34:36'),('965afc31-487a-498e-9fdd-e4b413c05e5b','marine-sustainability-report-2026','Sustainability: 2026 Environmental Compliance Report Released','NEWS','<h2><span class=\"ql-font-serif\">Exceeding MARPOL Standards</span></h2><p><span class=\"ql-font-serif\">Our annual report on global vessel compliance reveals a 15% improvement in emission reduction among the Girik-classed fleet.</span></p><p><span class=\"ql-font-serif\">We continue to advise our clients on technical upgrades to meet upcoming IMO greenhouse gas reduction targets.</span></p>','https://cdn.grclass.com/website/thumbnails/a26b95ee-cf2b-406f-8a5e-f8a1f1a15a1e-screen 2.png',NULL,1,'2026-04-18 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 09:18:02','2026-04-10 03:45:49'),('a1690e89-c30b-4bd2-a093-dbba6f686c04','about-us','About Girik Class – Excellence in Maritime Classification','PAGE','<h1 class=\"ql-indent-1\">ABOUT US</h1><h2 class=\"ql-indent-1\">Introduction</h2><p class=\"ql-indent-1\">GR Class is a modern maritime classification society committed to delivering reliable, efficient, and technology-driven solutions for vessel classification, certification, and regulatory compliance. The organization operates with a strong focus on safety, transparency, and global standards, supporting the maritime industry in meeting increasingly complex regulatory requirements.</p><p class=\"ql-indent-1\">GR Class combines deep domain expertise with advanced digital infrastructure to simplify compliance processes and enhance operational efficiency for ship owners, operators, and maritime stakeholders worldwide.</p><h2 class=\"ql-indent-1\">Vision</h2><p class=\"ql-indent-1\">To establish a globally trusted and digitally enabled maritime ecosystem where compliance processes are seamless, transparent, and universally verifiable.</p><h2 class=\"ql-indent-1\">Mission</h2><p class=\"ql-indent-1\">GR Class is dedicated to:</p><ul><li class=\"ql-indent-1\">Providing accurate and reliable classification and certification services</li><li class=\"ql-indent-1\">Enhancing maritime safety through strict adherence to international standards</li><li class=\"ql-indent-1\">Integrating modern technology into traditional maritime processes</li><li class=\"ql-indent-1\">Delivering efficient, transparent, and accessible compliance solutions</li><li class=\"ql-indent-1\">Building long-term relationships based on trust, integrity, and performance</li></ul><h2 class=\"ql-indent-1\">Organizational Expertise</h2><p class=\"ql-indent-1\">GR Class is supported by a team of qualified marine surveyors, engineers, and compliance specialists with extensive industry experience. The organization maintains a strong operational framework that ensures consistent service delivery across different regions and jurisdictions.</p><p class=\"ql-indent-1\">The team is equipped to handle a wide range of technical assessments, inspections, and audits, ensuring that vessels meet all applicable international conventions and regulatory requirements.</p><h2 class=\"ql-indent-1\">Global Operations</h2><p class=\"ql-indent-1\">GR Class operates across multiple geographical regions, providing services through a network of experienced professionals and strategic partnerships. This global presence enables:</p><ul><li class=\"ql-indent-1\">Timely inspection and certification services</li><li class=\"ql-indent-1\">Consistent application of international standards</li><li class=\"ql-indent-1\">Efficient coordination with maritime authorities and stakeholders</li><li class=\"ql-indent-1\">Continuous support for clients operating across different jurisdictions</li></ul><h2 class=\"ql-indent-1\">Core Services</h2><h3 class=\"ql-indent-1\">Classification Services</h3><p class=\"ql-indent-1\">GR Class provides vessel classification based on structural integrity, safety standards, and operational performance. These services ensure that vessels meet established technical criteria throughout their lifecycle.</p><h3 class=\"ql-indent-1\">Statutory Certification</h3><p class=\"ql-indent-1\">The organization issues statutory certificates in compliance with international maritime conventions and flag state requirements, ensuring legal and operational readiness of vessels.</p><h3 class=\"ql-indent-1\">Surveys and Inspections</h3><p class=\"ql-indent-1\">Comprehensive surveys and inspections are conducted to verify compliance with safety, environmental, and operational standards. These include periodic, renewal, and special surveys.</p><h3 class=\"ql-indent-1\">Technical Advisory</h3><p class=\"ql-indent-1\">GR Class offers expert advisory services to support vessel design, modification, retrofitting, and compliance planning.</p><h3 class=\"ql-indent-1\">Transfer of Class</h3><p class=\"ql-indent-1\">The organization facilitates the smooth transfer of vessels into its classification system, ensuring minimal disruption and full compliance continuity.</p><h2 class=\"ql-indent-1\">Digital Transformation</h2><p class=\"ql-indent-1\">GR Class adopts a digital-first approach to maritime certification and compliance. The organization utilizes secure and scalable technologies to:</p><ul><li class=\"ql-indent-1\">Issue digitally verifiable certificates</li><li class=\"ql-indent-1\">Maintain centralized compliance records</li><li class=\"ql-indent-1\">Enable real-time access to certification data</li><li class=\"ql-indent-1\">Reduce dependency on manual documentation</li><li class=\"ql-indent-1\">Improve transparency and operational efficiency</li></ul><h2 class=\"ql-indent-1\">Quality and Compliance Commitment</h2><p class=\"ql-indent-1\">Quality assurance is a fundamental aspect of GR Class operations. The organization follows strict internal and external standards to ensure the highest level of service delivery. This includes:</p><ul><li class=\"ql-indent-1\">Regular audits and performance evaluations</li><li class=\"ql-indent-1\">Continuous professional training and development</li><li class=\"ql-indent-1\">Implementation of internationally recognized best practices</li><li class=\"ql-indent-1\">Ongoing monitoring and improvement of operational processes</li></ul><h2 class=\"ql-indent-1\">Core Values</h2><ul><li class=\"ql-indent-1\">Integrity: Maintaining transparency and ethical conduct in all operations</li><li class=\"ql-indent-1\">Reliability: Delivering consistent and dependable services</li><li class=\"ql-indent-1\">Innovation: Leveraging technology to improve efficiency and effectiveness</li><li class=\"ql-indent-1\">Safety: Prioritizing human life, environmental protection, and operational security</li><li class=\"ql-indent-1\">Excellence: Striving for the highest standards in all aspects of service delivery</li></ul><h2 class=\"ql-indent-1\">Future Direction</h2><p class=\"ql-indent-1\">GR Class is focused on continuous growth and innovation. The organization aims to expand its global reach, enhance digital capabilities, and introduce advanced solutions that further streamline maritime compliance and certification processes.</p>','',NULL,1,'2026-04-04 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 09:17:58','2026-04-10 03:08:12'),('abf2b930-59b3-43cb-ba0e-b6a2e29f0e8c','blockchain-certificate-verification-launch','Technology: Immutable Blockchain Verification Now Live','NEWS','<h2>Ending Maritime Fraud</h2><p>Girik Class has successfully integrated blockchain technology into its digital certification pipeline.</p><p>Every certificate issued from today onwards will be permanently anchored to a secure ledger, allowing Port State Control and shipowners to verify authenticity in seconds without contacting our head office.</p>','website/thumbnails/dc113eeb-ea32-4020-9f4e-0091ff06eb17-screen.png',NULL,1,'2026-04-07 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 09:18:02','2026-04-07 16:30:42'),('d4371572-6d45-41ec-8657-33b9ad401415','terms-and-condition','Terms and condition','PAGE','<h1>1. Introduction and Acceptance</h1><p>These Terms and Conditions (“Terms”) constitute a legally binding agreement between <strong>GRClass</strong> (“Company”, “We”, “Us”, or “Our”) and any individual or entity accessing or using the GRClass platform (“User”, “You”, or “Your”).</p><p>These Terms govern your access to and use of the GRClass digital platform, including but not limited to certification management, survey coordination, compliance tracking, reporting tools, and financial modules (collectively, the “Platform”).</p><p>By accessing or using the Platform, you confirm that you have read, understood, and agree to be bound by these Terms. If you do not agree with any part of these Terms, you must immediately discontinue use of the Platform.</p><h1>2. Scope of Service</h1><p>GRClass provides a digital infrastructure designed for maritime classification, inspection coordination, and certification lifecycle management, including:</p><h3>Certification Lifecycle</h3><ul><li>Requesting vessel certification</li><li>Technical review and approval workflow</li><li>Digital issuance and lifecycle tracking</li><li>Renewal and expiry management</li></ul><h3>Survey Management</h3><ul><li>Survey job requests and scheduling</li><li>Surveyor assignment and tracking</li><li>Inspection data submission</li><li>Evidence and report management</li></ul><h3>Compliance Tracking</h3><ul><li>Regulatory monitoring</li><li>Certificate validity tracking</li><li>Deficiency management</li><li>Compliance status dashboards</li></ul><h3>Financial Operations</h3><ul><li>Invoice generation and tracking</li><li>Payment status monitoring</li><li>Certification release upon payment clearance</li></ul><p><strong>Important:</strong> GRClass functions primarily as a digital facilitator and technical coordination platform. Physical inspections are performed only when covered under a separate service agreement or authorized survey arrangement.</p><h1>3. User Roles and Access Control</h1><p>The Platform operates using <strong>Role-Based Access Control (RBAC)</strong> to ensure data security and operational integrity. User roles may include:</p><ul><li>Client (Ship Owners / Managers)</li><li>Surveyor (Inspection Personnel)</li><li>Technical Staff (TO, TM, GM)</li><li>Administrator (System Management)</li></ul><p>Each user is granted permissions based strictly on their assigned role.</p><p>Users agree to:</p><ul><li>Access only authorized modules</li><li>Not attempt privilege escalation</li><li>Not access restricted data</li><li>Not manipulate system workflows</li></ul><p>Any attempt to bypass security controls or access unauthorized information may result in:</p><ul><li>Immediate account suspension</li><li>Permanent termination</li><li>Legal action if required</li></ul><h1>4. Account Responsibility and Security</h1><h3>Credential Responsibility</h3><p>Users are responsible for maintaining the confidentiality of login credentials. All activities performed under a user account are considered the responsibility of that account holder.</p><h3>Data Accuracy</h3><p>Users must provide accurate, complete, and up-to-date information during registration and platform usage.</p><h3>Unauthorized Access</h3><p>Users must immediately notify GRClass in case of:</p><ul><li>Suspected account compromise</li><li>Unauthorized access</li><li>Suspicious activity</li><li>Credential leakage</li></ul><p>GRClass shall not be liable for losses resulting from compromised user credentials.</p><h1>5. Job Requests and Survey Protocols</h1><h3>Request Submission</h3><p>Clients may submit vessel survey requests through the platform dashboard.</p><h3>Approval Discretion</h3><p>GRClass reserves the right to:</p><ul><li>Approve or reject survey requests</li><li>Assign surveyors</li><li>Request additional documentation</li><li>Modify survey scope</li></ul><h3>Surveyor Responsibilities</h3><p>Surveyors must:</p><ul><li>Submit accurate inspection findings</li><li>Provide supporting evidence</li><li>Upload photographs and documentation</li><li>Follow technical reporting standards</li></ul><h3>Report Verification</h3><p>GRClass may request:</p><ul><li>Report revision</li><li>Additional evidence</li><li>Re-inspection</li><li>Technical clarification</li></ul><p>If submitted reports do not meet technical standards.</p><h1>6. Certification Issuance and Validity</h1><p>Certificates are issued digitally based on:</p><ul><li>Successful survey completion</li><li>Technical review approval</li><li>Compliance verification</li><li>Payment confirmation</li></ul><h3>Certificate Validity</h3><p>Certificates are valid only for:</p><ul><li>The specified vessel</li><li>Defined scope</li><li>Mentioned duration</li><li>Applicable regulations</li></ul><h3>Revocation Rights</h3><p>GRClass reserves the right to:</p><ul><li>Suspend certificates</li><li>Modify certification scope</li><li>Revoke certificates</li><li>Place certificates on hold</li></ul><p>If:</p><ul><li>Non-compliance is detected</li><li>False data is submitted</li><li>Payment disputes arise</li><li>Regulatory requirements change</li></ul><h1>7. Financial Terms</h1><h3>Fees</h3><p>Users agree to pay all applicable fees related to:</p><ul><li>Surveys</li><li>Certification</li><li>Documentation</li><li>Technical services</li></ul><p>As per the current GRClass fee schedule.</p><h3>Payment Requirement</h3><p>Unless otherwise agreed in writing:</p><p>Certificates will remain in <strong>Pending Status</strong> until full payment is received.</p><h3>Late Payments</h3><p>GRClass reserves the right to:</p><ul><li>Suspend certificate issuance</li><li>Restrict platform access</li><li>Block new requests</li><li>Apply late payment restrictions</li></ul><p>For overdue invoices.</p><h1>8. Data Accuracy and Audit</h1><h3>User Responsibility</h3><p>Users remain responsible for:</p><ul><li>Vessel details accuracy</li><li>Uploaded documents</li><li>Technical information submitted</li><li>Compliance declarations</li></ul><h3>Audit Logs</h3><p>The platform maintains audit logs of:</p><ul><li>User login activity</li><li>Data changes</li><li>Certificate issuance</li><li>Survey submissions</li><li>System actions</li></ul><p>By using the platform, users consent to monitoring and auditing for:</p><ul><li>Security</li><li>Compliance</li><li>Regulatory requirements</li><li>Dispute resolution</li></ul><h1>9. Platform Availability and Maintenance</h1><p>GRClass targets high availability but does not guarantee:</p><ul><li>Uninterrupted access</li><li>Real-time processing</li><li>Immediate certificate issuance</li><li>Continuous uptime during maintenance</li></ul><p>The platform may experience:</p><ul><li>Scheduled maintenance</li><li>Emergency downtime</li><li>Server load delays</li><li>System upgrades</li></ul><p>GRClass shall not be liable for temporary unavailability.</p><h1>10. Limitation of Liability</h1><p>To the maximum extent permitted by law, GRClass shall not be liable for:</p><ul><li>Vessel operational losses</li><li>Business interruption</li><li>Survey delays</li><li>Regulatory authority decisions</li><li>Port State Control penalties</li><li>Flag State penalties</li><li>Certification delays</li><li>Third-party surveyor performance</li><li>Indirect or consequential damages</li></ul><p>Use of the platform is at the user\'s own risk.</p><h1>11. Intellectual Property</h1><p>All rights related to the platform remain the exclusive property of GRClass, including:</p><ul><li>Platform architecture</li><li>UI/UX design</li><li>Technical workflows</li><li>Survey templates</li><li>Certification formats</li><li>Algorithms</li><li>Database structure</li></ul><p>Users may not:</p><ul><li>Copy the system</li><li>Reverse engineer</li><li>Replicate workflows</li><li>Resell access</li><li>Distribute reports without permission</li></ul><p>Without prior written consent from GRClass.</p><h1>12. Confidentiality</h1><p>All information processed through the platform is considered confidential, including:</p><ul><li>Vessel data</li><li>Survey reports</li><li>Technical findings</li><li>Certification records</li><li>Client information</li></ul><p>Users agree not to:</p><ul><li>Share reports externally</li><li>Distribute screenshots</li><li>Share login access</li><li>Disclose internal workflows</li></ul><p>Without authorization.</p><p>GRClass maintains industry-standard security and encryption measures.</p><h1>13. Governing Law and Jurisdiction</h1><p>These Terms shall be governed by and interpreted in accordance with the laws of India.</p><p>Any disputes arising from these Terms shall be subject to the exclusive jurisdiction of the courts in <strong>Mumbai, India</strong>.</p><h1>14. Contact Information</h1><p>For legal, technical, or platform-related inquiries:</p><p><strong>GRClass Support Team</strong></p><p>Email: support@grclass.com</p><p><br></p><p>Address: PLC Mumbai</p><p>Website: <a href=\"http://www.grclass.com\" rel=\"noopener noreferrer\" target=\"_blank\">www.grclass.com</a></p><h1>Acknowledgement</h1><p>By accessing or using the GRClass Platform, you acknowledge that:</p><ul><li>You have read these Terms</li><li>You understand these Terms</li><li>You agree to these Terms</li><li>You accept all responsibilities outlined herein</li></ul><p>Your continued use of the platform constitutes full acceptance of these Terms and Conditions.</p>','',NULL,1,'2026-04-04 00:00:00','019c79a4-3eee-731a-9eff-b0eed303e215','2026-04-04 10:18:27','2026-04-10 04:17:56');
